841	// ClearCooldowns clears execute-loop cooldown fields for all beads matched by
842	// filter. If filter is nil, every bead with execute-loop-retry-after set is
843	// cleared. Returns the count of beads whose cooldowns were cleared. A
844	// "cooldown-cleared" event with reason="operator-bulk-clear" is appended for
845	// each cleared bead in the same pass.
846	func (s *Store) ClearCooldowns(filter func(Bead) bool) (int, error) {
847		var count int
848		err := s.WithLock(func() error {
849			beads, _, err := s.readAllLatestRaw()
850			if err != nil {
851				return err
852			}
853			now := time.Now().UTC()
854			for i := range beads {
855				b := &beads[i]
856				if extraStringVal(b.Extra, ExtraRetryAfter) == "" {
857					continue
858				}
859				if filter != nil && !filter(*b) {
860					continue
861				}
862				if b.Extra == nil {
863					b.Extra = make(map[string]any)
864				}
865				delete(b.Extra, ExtraRetryAfter)
866				delete(b.Extra, ExtraLastStatus)
867				delete(b.Extra, ExtraLastDetail)
868				b.UpdatedAt = now
869				var events []BeadEvent
870				if raw, ok := b.Extra["events"]; ok {
871					events = decodeBeadEvents(raw)
872				}
873				events = append(events, BeadEvent{
874					Kind:      "cooldown-cleared",
875					Summary:   "operator-bulk-clear",
876					Source:    "ddx work clear-cooldowns",
877					CreatedAt: now,
878				})
879				b.Extra["events"] = encodeEventsForExtra(events)

