34	// commitOutcome keeps the drain loop moving after a post-outcome store failure.
35	// The wrapped op supplies the operation label via commitOutcomeError so this
36	// helper can preserve the loop-error event and cooldown behavior without
37	// hard-erroring the worker or surfacing the store error to Drain.
38	func commitOutcome(ctx context.Context, store ExecuteBeadLoopStore, beadID string, op func() error) error {
39		if err := op(); err != nil {
40			var failure *commitOutcomeFailure
41			if errors.As(err, &failure) {
42				if failure.result != nil {
43					failure.result.Failures++
44					failure.result.LastFailureStatus = "loop-error"
45				}
46				_ = store.AppendEvent(beadID, bead.BeadEvent{
47					Kind:      "loop-error",
48					Summary:   failure.operation + " failed",
49					Body:      failure.err.Error(),
50					Actor:     failure.assignee,
51					Source:    "ddx agent execute-loop",
52					CreatedAt: time.Now().UTC(),
53				})
54				_ = store.SetExecutionCooldown(beadID, time.Now().UTC().Add(StoreErrorCooldown), "loop-error", failure.operation+": "+failure.err.Error())
55				return nil
56			}
57			_ = store.SetExecutionCooldown(beadID, time.Now().UTC().Add(StoreErrorCooldown), "loop-error", err.Error())
58			return nil
59		}
60		return nil
61	}
